var a = ArmyListManager.load_army_list("custodes_web_built_repro", 1)
if a.is_empty():
	return "LOAD_FAILED"
GameState.state["units"] = a["units"]
return GameState.unit_has_deep_strike("U_CUSTODIAN_GUARD_A")

var a = ArmyListManager.load_army_list("custodes_web_built_repro", 1)
GameState.state["units"] = a["units"]
if not GameState.state.has("meta"):
	GameState.state["meta"] = {}
GameState.state["meta"]["active_player"] = 1
var dlg = AcceptDialog.new()
dlg.set_script(load("res://scripts/FormationsDeclarationDialog.gd"))
tree.root.add_child(dlg)
dlg.setup(1)
dlg.popup_centered()
var rt = "NOT_FOUND"
var stack = [dlg]
while not stack.is_empty():
	var n = stack.pop_back()
	for c in n.get_children():
		stack.append(c)
		if c is CheckBox and c.has_meta("unit_id") and c.get_meta("unit_id") == "U_CUSTODIAN_GUARD_A":
			rt = str(c.get_meta("reserve_type"))
return rt

var a = ArmyListManager.load_army_list("custodes_lions", 1)
GameState.state["units"] = a["units"]
var res = "NOT_FOUND"
for uid in a["units"]:
	if GameState.get_unit(uid).get("meta",{}).get("name","") == "Prosecutors":
		res = str(GameState.unit_has_deep_strike(uid))
return res
